import type { PaginationParams, PaginatedResponse, Product, Category } from '~/types'

export function useProductsApi() {
    const { $api } = useNuxtApp()
    return {
        findAll(params?: PaginationParams & { category?: string }) { return $api<PaginatedResponse<Product>>('/products', { params }) },
        findBySlug(slug: string) { return $api<Product>(`/products/slug/${slug}`) },
        findById(id: string) { return $api<Product>(`/products/${id}`) },
        getCategories() { return $api<Category[]>('/products/categories/all') },
    }
}
